BEGIN;

-- Transfer $100 from account 1 to account 2
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;

-- Verify both updates are valid
DO $$
BEGIN
    IF (SELECT balance FROM accounts WHERE id = 1) < 0 THEN
        RAISE EXCEPTION 'Insufficient funds';
    END IF;
END $$;

COMMIT;
-- If any error occurs, PostgreSQL auto-ROLLBACKs

-- Isolation levels
SET TRANSACTION ISOLATION LEVEL READ COMMITTED; -- default
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;   -- strictest

-- Optimistic locking with version column
UPDATE products
SET stock = stock - 1, version = version + 1
WHERE id = 123 AND version = 5;

-- Check if update succeeded (0 rows = version mismatch)
-- If 0 rows, another transaction modified it — retry

-- Savepoints — partial rollback
BEGIN;
INSERT INTO orders (customer_id, total) VALUES (1, 100);
SAVEPOINT order_created;

INSERT INTO order_items (order_id, product_id, quantity)
VALUES (1, 1, 5);

-- If item insert fails:
ROLLBACK TO SAVEPOINT order_created;
-- Order still exists, but item was rolled back

COMMIT;

-- Advisory locks (application-level locking)
SELECT pg_advisory_lock(12345);  -- acquire lock
-- ... critical section ...
SELECT pg_advisory_unlock(12345); -- release lock
```

