-- JSONB — flexible schema
CREATE TABLE events (
    id SERIAL PRIMARY KEY,
    event_type VARCHAR(50) NOT NULL,
    payload JSONB NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

INSERT INTO events (event_type, payload) VALUES
('page_view', '{"url": "/home", "user_id": 42, "duration": 120}'),
('purchase', '{"items": ["book", "pen"], "total": 25.50, "user_id": 42}');

-- Query JSONB fields
SELECT
    event_type,
    payload->>'url' AS url,                  -- text extraction
    (payload->>'duration')::INT AS duration,  -- typed extraction
    payload->'items' AS items                 -- JSON extraction
FROM events
WHERE payload @> '{"user_id": 42}';          -- containment

-- GIN index for fast JSONB queries
CREATE INDEX idx_events_payload ON events USING GIN (payload);

-- Array operations
CREATE TABLE articles (
    id SERIAL PRIMARY KEY,
    title VARCHAR(200) NOT NULL,
    tags TEXT[] NOT NULL DEFAULT '{}'
);

INSERT INTO articles (title, tags) VALUES
('Intro to SQL', '{"sql", "database", "tutorial"}'),
('Advanced Python', '{"python", "programming", "tutorial"}');

SELECT * FROM articles WHERE 'tutorial' = ANY(tags);
SELECT * FROM articles WHERE tags @> ARRAY['sql'];
SELECT unnest(tags) AS tag, COUNT(*) FROM articles GROUP BY tag;

-- Full-text search
ALTER TABLE articles ADD COLUMN search_vector TSVECTOR;

UPDATE articles SET search_vector =
    to_tsvector('english', title || ' ' || array_to_string(tags, ' '));

CREATE INDEX idx_articles_fts ON articles USING GIN (search_vector);

SELECT title, ts_rank(search_vector, query) AS rank
FROM articles, to_tsquery('english', 'sql & tutorial') query
WHERE search_vector @@ query
ORDER BY rank DESC;
```
